"use client";

import { useState } from "react";
import Navbar from "@/app/components/Navbar";
import Footer from "@/app/components/Footer";

export default function SalaryCalculatorPage() {
    const [salary, setSalary] = useState("");
    const [salaryType, setSalaryType] = useState<"gross" | "net">("gross");

    const calculateSalary = () => {
        const baseSalary = parseFloat(salary.replace(/,/g, "")) || 0;

        if (salaryType === "gross") {
            const socialIns = baseSalary * 0.08;
            const healthIns = baseSalary * 0.015;
            const unemploymentIns = baseSalary * 0.01;
            const taxIncome = baseSalary - socialIns - healthIns - unemploymentIns - 11000000;

            let personalTax = 0;
            if (taxIncome > 0) {
                if (taxIncome <= 5000000) personalTax = taxIncome * 0.05;
                else if (taxIncome <= 10000000) personalTax = 250000 + (taxIncome - 5000000) * 0.1;
                else if (taxIncome <= 18000000) personalTax = 750000 + (taxIncome - 10000000) * 0.15;
                else if (taxIncome <= 32000000) personalTax = 1950000 + (taxIncome - 18000000) * 0.2;
                else if (taxIncome <= 52000000) personalTax = 4750000 + (taxIncome - 32000000) * 0.25;
                else if (taxIncome <= 78000000) personalTax = 9750000 + (taxIncome - 52000000) * 0.3;
                else personalTax = 17550000 + (taxIncome - 78000000) * 0.35;
            }

            const netSalary = baseSalary - socialIns - healthIns - unemploymentIns - personalTax;
            return { gross: baseSalary, net: netSalary, socialIns, healthIns, unemploymentIns, personalTax, takeHome: netSalary };
        } else {
            const gross = baseSalary * 1.2;
            const socialIns = gross * 0.08;
            const healthIns = gross * 0.015;
            const unemploymentIns = gross * 0.01;
            const taxIncome = gross - socialIns - healthIns - unemploymentIns - 11000000;

            let personalTax = 0;
            if (taxIncome > 0) {
                if (taxIncome <= 5000000) personalTax = taxIncome * 0.05;
                else if (taxIncome <= 10000000) personalTax = 250000 + (taxIncome - 5000000) * 0.1;
                else if (taxIncome <= 18000000) personalTax = 750000 + (taxIncome - 10000000) * 0.15;
                else if (taxIncome <= 32000000) personalTax = 1950000 + (taxIncome - 18000000) * 0.2;
                else if (taxIncome <= 52000000) personalTax = 4750000 + (taxIncome - 32000000) * 0.25;
                else if (taxIncome <= 78000000) personalTax = 9750000 + (taxIncome - 52000000) * 0.3;
                else personalTax = 17550000 + (taxIncome - 78000000) * 0.35;
            }

            return { gross, net: baseSalary, socialIns: gross * 0.08, healthIns: gross * 0.015, unemploymentIns: gross * 0.01, personalTax, takeHome: baseSalary };
        }
    };

    const result = salary ? calculateSalary() : null;

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(amount);
    };

    return (
        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
            <Navbar />

            {/* Page Header */}
            <div style={{ background: "var(--page-header-bg)", borderBottom: "1.5px solid var(--border)", padding: "3rem 0" }}>
                <div className="container-xl" style={{ textAlign: "center", maxWidth: "800px" }}>
                    <h1 style={{ fontSize: "clamp(1.5rem, 3vw, 2rem)", fontWeight: 800, color: "var(--text)", marginBottom: "0.5rem" }}>
                        Tính lương Net → Gross
                    </h1>
                    <p style={{ color: "var(--text-muted)", fontSize: "1.0625rem" }}>
                        Tính toán lương thực nhận từ lương Gross hoặc ngược lại
                    </p>
                </div>
            </div>

            <main style={{ flex: 1, background: "var(--bg)", padding: "2rem 0" }}>
                <div className="container-xl">
                    <div style={{ maxWidth: "800px", margin: "0 auto" }}>
                        <div className="card" style={{ padding: "2rem" }}>
                            {/* Salary Type Toggle */}
                            <div style={{ display: "flex", gap: "0.5rem", marginBottom: "1.5rem", background: "var(--bg)", padding: "0.25rem", borderRadius: "8px" }}>
                                <button
                                    onClick={() => setSalaryType("gross")}
                                    style={{
                                        flex: 1, padding: "0.75rem", border: "none", borderRadius: "6px",
                                        background: salaryType === "gross" ? "var(--primary)" : "transparent",
                                        color: salaryType === "gross" ? "#fff" : "var(--text-muted)",
                                        fontWeight: 600, cursor: "pointer", transition: "all 0.2s"
                                    }}
                                >
                                    Lương Gross
                                </button>
                                <button
                                    onClick={() => setSalaryType("net")}
                                    style={{
                                        flex: 1, padding: "0.75rem", border: "none", borderRadius: "6px",
                                        background: salaryType === "net" ? "var(--primary)" : "transparent",
                                        color: salaryType === "net" ? "#fff" : "var(--text-muted)",
                                        fontWeight: 600, cursor: "pointer", transition: "all 0.2s"
                                    }}
                                >
                                    Lương Net
                                </button>
                            </div>

                            {/* Salary Input */}
                            <div style={{ marginBottom: "1.5rem" }}>
                                <label style={{ display: "block", fontSize: "0.875rem", fontWeight: 600, color: "var(--text)", marginBottom: "0.5rem" }}>
                                    Nhập lương ({salaryType === "gross" ? "Gross" : "Net"}) của bạn
                                </label>
                                <input
                                    type="text"
                                    value={salary}
                                    onChange={(e) => setSalary(e.target.value.replace(/[^0-9]/g, ""))}
                                    placeholder="Ví dụ: 20000000"
                                    style={{
                                        width: "100%", padding: "0.875rem 1rem", borderRadius: "8px",
                                        border: "1.5px solid var(--border)", background: "var(--bg-card)",
                                        color: "var(--text)", fontSize: "1rem", outline: "none",
                                    }}
                                />
                                <p style={{ fontSize: "0.8125rem", color: "var(--text-muted)", marginTop: "0.5rem" }}>
                                    {salaryType === "gross"
                                        ? "Lương Gross là tổng lương trước thuế và bảo hiểm"
                                        : "Lương Net là số tiền bạn thực nhận hàng tháng"
                                    }
                                </p>
                            </div>

                            {/* Results */}
                            {result && (
                                <div style={{ marginTop: "2rem" }}>
                                    <h3 style={{ fontSize: "1rem", fontWeight: 700, color: "var(--text)", marginBottom: "1rem" }}>
                                        Kết quả tính toán
                                    </h3>
                                    <div style={{ display: "grid", gap: "1rem" }}>
                                        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "1rem" }}>
                                            <div style={{ padding: "1rem", background: "var(--primary)", borderRadius: "8px", color: "#fff" }}>
                                                <div style={{ fontSize: "0.8125rem", opacity: 0.9, marginBottom: "0.25rem" }}>Lương Gross</div>
                                                <div style={{ fontSize: "1.25rem", fontWeight: 700 }}>{formatCurrency(result.gross)}</div>
                                            </div>
                                            <div style={{ padding: "1rem", background: "var(--cta)", borderRadius: "8px", color: "#fff" }}>
                                                <div style={{ fontSize: "0.8125rem", opacity: 0.9, marginBottom: "0.25rem" }}>Lương Net (Thực nhận)</div>
                                                <div style={{ fontSize: "1.25rem", fontWeight: 700 }}>{formatCurrency(result.takeHome)}</div>
                                            </div>
                                        </div>
                                        <div style={{ padding: "1rem", background: "var(--bg)", borderRadius: "8px" }}>
                                            <h4 style={{ fontSize: "0.875rem", fontWeight: 600, color: "var(--text)", marginBottom: "0.75rem" }}>
                                                Các khoản khấu trừ
                                            </h4>
                                            <div style={{ display: "grid", gap: "0.5rem" }}>
                                                {[
                                                    { label: "Bảo hiểm xã hội (8%)", value: result.socialIns },
                                                    { label: "Bảo hiểm y tế (1.5%)", value: result.healthIns },
                                                    { label: "Bảo hiểm thất nghiệp (1%)", value: result.unemploymentIns },
                                                ].map((item) => (
                                                    <div key={item.label} style={{ display: "flex", justifyContent: "space-between", fontSize: "0.875rem" }}>
                                                        <span style={{ color: "var(--text-muted)" }}>{item.label}</span>
                                                        <span style={{ fontWeight: 600, color: "var(--text)" }}>- {formatCurrency(item.value)}</span>
                                                    </div>
                                                ))}
                                                <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.875rem", paddingTop: "0.5rem", borderTop: "1px solid var(--border)" }}>
                                                    <span style={{ color: "var(--text-muted)" }}>Thuế TNCN (nếu có)</span>
                                                    <span style={{ fontWeight: 600, color: "var(--text)" }}>- {formatCurrency(result.personalTax)}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    <p style={{ fontSize: "0.8125rem", color: "var(--text-muted)", marginTop: "1rem", textAlign: "center" }}>
                                        * Đây là tính toán ước lượng, có thể không chính xác 100%
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </main>

            <Footer />
        </div>
    );
}
